framework_css:
/*
  Global Design System
  Matches the AI chatbot SaaS hero style:
  - White canvas with vibrant gradient blobs
  - Strong purple branding and navigation
  - Bold geometric headings, clean sans-serif body
*/

/* CSS Reset / Base */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", Arial, sans-serif;
  color: #333843;
  background-color: #ffffff;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
}

ul {
  list-style: none;
  margin: 0;
  padding: 0;
}

a {
  color: inherit;
}

:root {
  /* Color palette from specification & visual sampling */
  --color-primary-500: #6A3EA1; /* main purple (logo, headings, active nav) */
  --color-primary-700: #4D2A78; /* darker purple */

  --color-secondary-blue: #1F4FEF; /* blob blue */
  --color-secondary-teal: #22C7C9; /* blob teal */

  --color-accent-orange: #FF8A00; /* blob orange start */
  --color-accent-red: #FF4B2B;   /* blob orange-red end */

  --color-neutral-0: #ffffff;
  --color-neutral-700: #333843;
  --color-neutral-900: #111827;

  --color-success: #22C55E;
  --color-error: #EF4444;
  --color-warning: #F59E0B;
  --color-info: #3B82F6;

  /* Typography */
  --font-heading: "Space Grotesk", -apple-system, BlinkMacSystemFont, "Helvetica", sans-serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", Arial, sans-serif;
  --font-code: "Source Code Pro", SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

  --font-size-h1: clamp(3rem, 5vw, 4rem); /* 48px–64px */
  --font-size-h2: clamp(2rem, 3vw, 2.5rem); /* 32px–40px */
  --font-size-h3: clamp(1.5rem, 2.5vw, 1.75rem); /* 24px–28px */
  --font-size-body: 1rem; /* 16px */
  --font-size-small: 0.8125rem; /* 13px */

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (4px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --header-height-desktop: 80px;
  --container-max-width: 1120px;
}

.container {
  width: 100%;
  max-width: var(--container-max-width);
  margin-inline: auto;
  padding-inline: var(--space-3);
}

/* Header */

.site-header {
  position: relative;
  z-index: 20;
  background-color: var(--color-neutral-0);
  box-shadow: 0 8px 24px rgba(15, 23, 42, 0.04);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: var(--header-height-desktop);
  gap: var(--space-4);
}

/* Brand / Logo area */

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
}

.brand-avatar {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 20%, #ffffff 0, #ffffff 18%, transparent 19%),
              radial-gradient(circle at 30% 80%, #ffffff 0, #ffffff 18%, transparent 19%),
              linear-gradient(135deg, #4D2A78 0%, #6A3EA1 50%, #1F4FEF 100%);
  box-shadow: 0 8px 20px rgba(15, 23, 42, 0.25);
}

.brand-text {
  display: flex;
  flex-direction: column;
  justify-content: center;
  line-height: 1.1;
}

.brand-name {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.12em;
  font-size: 1.125rem;
  color: var(--color-primary-500);
  text-transform: uppercase;
}

.brand-tagline {
  font-family: var(--font-body);
  font-size: 0.8125rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(17, 24, 39, 0.7);
}

/* Main navigation */

.main-nav {
  font-family: var(--font-body);
}

.nav-list {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.nav-link {
  position: relative;
  display: inline-flex;
  align-items: center;
  font-size: 0.9375rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-neutral-900);
  text-decoration: none;
  padding-block: var(--space-1);
  transition: color 160ms ease;
}

.nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 2px;
  border-radius: 999px;
  background-color: var(--color-primary-500);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 160ms ease;
}

.nav-link:hover,
.nav-link:focus-visible {
  color: var(--color-primary-500);
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
  transform: scaleX(1);
}

.nav-link--active {
  color: var(--color-primary-500);
}

.nav-link--active::after {
  transform: scaleX(1);
}

.nav-link:focus-visible {
  outline: 2px solid var(--color-primary-500);
  outline-offset: 2px;
}

/* Main content area / hero background frame */

.site-main {
  position: relative;
  min-height: calc(100vh - 220px); /* leaves room for header + footer */
  padding-block: var(--space-6);
  background-color: var(--color-neutral-0);
  overflow: hidden;

  /* Gradient blobs constructed as layered radial-gradients
     to mimic the hero illustration across all pages. */
  background-image:
    radial-gradient(circle at 0% 100%, rgba(34, 199, 201, 0.95) 0, rgba(34, 199, 201, 0.2) 35%, rgba(34, 199, 201, 0) 60%),
    radial-gradient(circle at 25% 120%, rgba(31, 79, 239, 0.95) 0, rgba(31, 79, 239, 0.25) 40%, rgba(31, 79, 239, 0) 65%),
    radial-gradient(circle at 100% 105%, rgba(255, 138, 0, 0.98) 0, rgba(255, 75, 43, 0.9) 40%, rgba(255, 75, 43, 0) 66%);
  background-repeat: no-repeat;
  background-size: 40% 70%, 45% 75%, 40% 70%;
  background-position: 0% 100%, 40% 120%, 100% 105%;
}

/* Ensure content inside main stays readable on top of blobs */
.site-main > * {
  position: relative;
  z-index: 1;
}

/* Footer */

.site-footer {
  background-color: var(--color-neutral-0);
  border-top: 1px solid #e5e7eb;
  padding-block: var(--space-4);
  font-family: var(--font-body);
}

.footer-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
  flex-wrap: wrap;
}

.footer-brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
}

.footer-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: linear-gradient(135deg, #4D2A78 0%, #6A3EA1 40%, #1F4FEF 100%);
  box-shadow: 0 6px 14px rgba(15, 23, 42, 0.18);
}

.footer-brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.footer-brand-name {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.16em;
  font-size: 0.95rem;
  text-transform: uppercase;
  color: var(--color-primary-500);
}

.footer-brand-tagline {
  font-size: 0.75rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(17, 24, 39, 0.65);
}

.footer-nav {
  font-size: 0.9rem;
}

.footer-links {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
}

.footer-link {
  text-decoration: none;
  color: rgba(17, 24, 39, 0.8);
  font-weight: var(--font-weight-medium);
  transition: color 150ms ease;
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-primary-500);
}

.footer-link:focus-visible {
  outline: 2px solid var(--color-primary-500);
  outline-offset: 2px;
}

.footer-bottom {
  margin-top: var(--space-3);
  border-top: 1px solid #f3f4f6;
  padding-top: var(--space-2);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-copy {
  margin: 0;
  font-size: 0.8125rem;
  color: rgba(17, 24, 39, 0.6);
}

/* Typography utility classes (optional for page content) */

.h1,
.h2,
.h3 {
  margin: 0;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  color: var(--color-primary-500);
}

.h2 {
  font-size: var(--font-size-h2);
}

.h3 {
  font-size: var(--font-size-h3);
}

.text-body {
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
}

.text-muted {
  color: rgba(17, 24, 39, 0.65);
}

/* Responsive adjustments */

@media (max-width: 900px) {
  .header-inner {
    flex-wrap: wrap;
    justify-content: center;
    padding-block: var(--space-2);
  }

  .brand {
    margin-bottom: var(--space-1);
  }

  .nav-list {
    gap: var(--space-2);
  }

  .site-main {
    padding-block: var(--space-5);
    background-size: 60% 60%, 70% 70%, 60% 60%;
    background-position: -10% 110%, 40% 120%, 110% 110%;
  }

  .footer-inner {
    align-items: flex-start;
  }

  .footer-bottom-inner {
    text-align: center;
  }
}

@media (max-width: 600px) {
  .header-inner {
    align-items: flex-start;
  }

  .main-nav {
    width: 100%;
  }

  .nav-list {
    justify-content: center;
    flex-wrap: wrap;
  }

  .footer-links {
    justify-content: center;
  }
}
